#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,h[10001],lh=0,ans=0;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>h[i];
        if(i==1)lh=i;
        else if(h[i]>h[i-1]){
            if(i-lh>1)ans++;
            lh=i;
        }
        //cout<<lh<<' '<<ans<<endl; 
    }
    cout<<ans;
    return 0;
}
